+    // vs FailNow = 100. Should pick RetryAfter(5ms) or lower.
+    if matches!(action, RetryAction::FailNow) {
+        return Err(format!(
+            "bead_id={BEAD_ID} case=argmin_not_cheapest action={action:?}"
+        ));
