+    eprintln!(
+        "WARN bead_id={BEAD_ID} case=e2e_degraded_mode degraded_mode=0 reference={LOG_STANDARD_REF}"
+    );
+    eprintln!(
+        "ERROR bead_id={BEAD_ID} case=e2e_terminal_failure_count terminal_failure_count=0 reference={LOG_STANDARD_REF}"
