+    let missing_e2e_ids = E2E_TEST_IDS
+        .into_iter()
+        .filter(|test_id| !contains_identifier(description, test_id))
+        .collect::<Vec<_>>();
+
+    let missing_phrases = {
+        let lowered = description.to_ascii_lowercase();
+        REQUIRED_PHRASES
+            .into_iter()
+            .filter(|phrase| !lowered.contains(phrase))
+            .collect::<Vec<_>>()
+    };
+
+    ComplianceEvaluation {
+        missing_unit_ids,
+        missing_e2e_ids,
+        missing_phrases,
+    }
+}
