+            cache.p(),
+            cache.b1_len(),
+            cache.b2_len()
+        );
+
+        // During learning phase, p should have adapted (moved from 0).
+        // Ghost lists should have entries.
+        let ghosts_populated = cache.b1_len() > 0 || cache.b2_len() > 0;
+        assert!(
+            ghosts_populated,
+            "bead_id={BEAD_ID_BD_2ZOA} case=warmup_phase2_learning \
